      JsRuntimeLib.instance.api.crateApiReplJsReplPendingCode(
        that: this,
      );

  /// 运行垃圾回收。
  void runGc() => JsRuntimeLib.instance.api.crateApiReplJsReplRunGc(
        that: this,
      );

  /// 获取内部运行时引用，用于直接执行 JS。
  Future<JsRuntime> runtime() =>
      JsRuntimeLib.instance.api.crateApiReplJsReplRuntime(
        that: this,
      );
}
